-- STEP 1: schema delta
ALTER TABLE public.ontology_categories
  ADD COLUMN IF NOT EXISTS keywords                  text[] NOT NULL DEFAULT '{}',
  ADD COLUMN IF NOT EXISTS example_entries           text[] NOT NULL DEFAULT '{}',
  ADD COLUMN IF NOT EXISTS co_occurring_category_ids uuid[] NOT NULL DEFAULT '{}';

CREATE UNIQUE INDEX IF NOT EXISTS ontology_categories_type_name_uk
  ON public.ontology_categories(type, normalized_name);

-- STEP 2: UPSERT 70 sub-categories
INSERT INTO public.ontology_categories
  (type, normalized_name, description, keywords, example_entries, sort_order, status)
VALUES
  ('capability', 'Business & Governance', 'Strategy, compliance, regulatory affairs, programme governance, and export-control management. Capabilities related to running a defence, security, or critical-infrastructure business end-to-end — distinct from building or operating systems.', ARRAY['strategy','compliance','governance','ITAR','EAR','dual-use','EU 2021/821','export control','NSM','security clearance','sikkerhetsklarering','EOS','programme management','BAFO','tender response','contract management','BRREG','GDPR','NIS2'], ARRAY['Strategic advisory','Regulatory compliance','Export control management','Programme governance','Risk & assurance'], 1, 'active'),
  ('capability', 'C4ISR, Communications & PNT', 'Command, control, communications, computers, intelligence, surveillance, reconnaissance, positioning, navigation, and timing — the joint information backbone of modern operations.', ARRAY['C2','C4','C4I','C4ISR','C5ISR','ISR','comms','SATCOM','GNSS','GPS','Galileo','PNT','A-PNT','STANAG 4586','STANAG 5066','tactical data link','Link 16','Link 22','BLOS','beyond-line-of-sight','FMN','federated mission networking'], ARRAY['Command and control','Tactical data links','SATCOM operations','GNSS/INS integration','ISR fusion'], 2, 'active'),
  ('capability', 'Cybersecurity', 'Defensive and offensive cyber operations, secure software development, OT/ICS security, security operations centres, and incident response across IT and operational technology.', ARRAY['cyber','cybersec','infosec','SOC','IR','SIEM','SOAR','zero-trust','OT security','ICS security','IT/OT convergence','ENISA','NIS2','CER directive','MITRE ATT&CK','threat intelligence','cryptography','ISO 27001','NSM grunnprinsipper'], ARRAY['Security operations centre','OT/ICS security','Secure software development','Incident response','Threat intelligence'], 3, 'active'),
  ('capability', 'Electronic Warfare', 'Electromagnetic spectrum operations — electronic support, electronic countermeasures, electronic counter-countermeasures, signals intelligence collection, and spectrum dominance.', ARRAY['EW','ESM','ECM','ECCM','SIGINT','ELINT','COMINT','jamming','spoofing','spectrum dominance','spectrum management','RF deception','electromagnetic battle management','EMBM','low-probability-of-intercept'], ARRAY['Electronic support measures','Electronic countermeasures','Spectrum operations','SIGINT collection','RF deception'], 4, 'active'),
  ('capability', 'Energy & Critical Infrastructure', 'Power generation and distribution, SCADA and industrial control, grid resilience, water utilities, pipeline integrity, subsea cables, and telecom backbones — both military critical infrastructure and civil critical infrastructure within the meaning of NIS2 and CER directive.', ARRAY['grid','SCADA','ICS','OT','NORSOK','NORSOK S-001','NORSOK U-100','NIS2','CER directive','critical infrastructure','kritisk infrastruktur','pipeline','water utility','vannverk','telecom backhaul','subsea cable','kraftforsyning','beredskapsforskriften','DSB'], ARRAY['Grid monitoring','SCADA hardening','Microgrid design','Pipeline integrity','Water utility resilience'], 5, 'active'),
  ('capability', 'Logistics, Supply Chain & Mobility', 'Movement of personnel, materiel, fuel, and equipment; deployable logistics; cold-chain handling; port, airport, and rail operations; host-nation support; strategic and tactical lift.', ARRAY['logistics','supply chain','sustainment','deployable','cold-chain','HNS','host-nation support','port operations','airfield operations','strategic lift','tactical lift','third-party logistics','3PL','ROLE-1 to ROLE-4 logistics support','prepositioning'], ARRAY['Deployable logistics','Fuel & energy supply','Cold-chain logistics','Port and airfield operations','Strategic lift coordination'], 6, 'active'),
  ('capability', 'Manufacturing & Engineering', 'Industrial production capabilities — machining, composites, additive manufacturing, welding, assembly, and qualification testing. The "make it" capability across components and platforms.', ARRAY['manufacturing','machining','composites','additive','AM','3D printing','welding','NDT','non-destructive testing','EN 9100','AS9100','ISO 9001','qualification','certification','production engineering','supply-chain manufacturing','defence industrial base','DIB'], ARRAY['Precision machining','Composite manufacturing','Additive manufacturing','Welding & assembly','NDT inspection'], 7, 'active'),
  ('capability', 'Maritime & Subsea', 'Surface vessel operations, sub-surface and subsea operations, port and harbour activities, offshore infrastructure, and subsea inspection and intervention — covering both naval/coastguard and offshore/oil-and-gas use cases.', ARRAY['maritime','naval','subsea','offshore','ROV','AUV','USV','hydrographic','oseanografi','NORSOK U-100','NORSOK U-101','vessel operations','port security','anti-submarine warfare','ASW','anti-surface warfare','ASuW','mine countermeasures','MCM','Arctic maritime','Svalbard','Barents'], ARRAY['Hydrographic survey','ROV operations','Subsea inspection','Vessel operations','Anti-submarine warfare'], 8, 'active'),
  ('capability', 'Platforms (Air, Land, Sea, Unmanned)', 'Design, integration, and operation of mobility platforms across air, land, sea, and unmanned domains. The "vehicle" side of the capability set, complementing the systems and effectors that ride on those platforms.', ARRAY['platform','airframe','hull','chassis','UAV','UGV','USV','AUV','vessel','vehicle','aircraft','MOTS','COTS','modular platform','dual-use platform','mission modularity','openness','F-35','NH90','P-8'], ARRAY['Fixed-wing aircraft integration','Rotary-wing integration','UAV systems integration','Naval vessel design','Armoured vehicle integration'], 9, 'active'),
  ('capability', 'Preparedness, Response & Medical', 'Civil protection, emergency preparedness, mass-casualty response, field medical and surgical capability, CBRN response, and search and rescue — covering Norwegian DSB "samfunnssikkerhet" remit and NATO RSOM-aligned medical capability.', ARRAY['preparedness','beredskap','samfunnssikkerhet','civil protection','SAR','search and rescue','MCI','mass casualty incident','CBRN response','decontamination','field hospital','ROLE-2','ROLE-3','DSB','Sivilforsvaret','NORTAT','evacuation','crisis communications','Totalforsvar'], ARRAY['Mass-casualty response','Field medical','CBRN decontamination','Search & rescue coordination','Evacuation planning'], 10, 'active'),
  ('capability', 'Sensors & Detection', 'Sensing systems across electro-optical, infrared, radar, sonar, LiDAR, RF, environmental, and CBRN modalities. Both wide-area surveillance and close-range detection use cases.', ARRAY['sensor','radar','sonar','LiDAR','EO','IR','EO/IR','hyperspectral','multispectral','CBRN detection','AIS','environmental monitoring','persistent surveillance','wide-area motion imagery','WAMI','ISR sensor','payload','gimbal'], ARRAY['Radar systems','EO/IR systems','Sonar','LiDAR systems','CBRN detection'], 11, 'active'),
  ('capability', 'Software, Systems & Integration', 'Mission software engineering, systems-of-systems integration, model-based engineering, DevSecOps for defence, and the digital glue that ties sensors, effectors, and command systems together.', ARRAY['software','systems integration','SoS','MBSE','DevSecOps','DevOps','agile','microservices','containers','Kubernetes','data fusion','middleware','API gateway','open architecture','FACE','OMS','UCS'], ARRAY['Mission systems software','Systems-of-systems integration','Model-based engineering','DevSecOps','Data fusion software'], 12, 'active'),
  ('capability', 'Space', 'Launch, satellite operations, ground segment, space situational awareness, earth observation, and SATCOM payload operations. Includes both space-based services and ground-based space-domain capabilities.', ARRAY['space','satellite','SSA','space situational awareness','ground segment','launch','LEO','MEO','GEO','EO satellite','SATCOM','smallsat','cubesat','KSAT','Andøya Space','Telenor Satellite'], ARRAY['Satellite operations','Ground segment','Space situational awareness','Earth observation','SATCOM payloads'], 13, 'active'),
  ('capability', 'Training & Simulation', 'Live, virtual, constructive (LVC) training; synthetic environments; serious-game design; exercise planning; and computer-assisted exercise (CAX) support.', ARRAY['training','simulation','LVC','live virtual constructive','synthetic environment','exercise','CAX','computer-assisted exercise','NATO CAX','JMSC','instructor-led','e-learning','AAR','after-action review'], ARRAY['Live training','Virtual simulation','Constructive simulation','Synthetic training environments','Exercise design'], 14, 'active'),
  ('capability', 'Weapons & Munitions', 'Effectors, munitions, fire-control systems, weapon-system integration, and explosive ordnance disposal — the "kinetic" side of the capability set.', ARRAY['weapon','munition','missile','effector','fire control','EOD','IED','explosive ordnance disposal','propulsion','warhead','ammunition','small arms','artillery','air defence','anti-tank','anti-ship','NAMMO','KONGSBERG'], ARRAY['Missile systems','Small arms','Ordnance disposal (EOD)','Fire control systems','Ammunition'], 15, 'active'),
  ('competence', 'Business & Governance', 'Strategic, programme, and contract management expertise — running defence, security, and critical-infrastructure businesses. Distinct from #15 Regulatory & Compliance, which covers narrower specialist roles in compliance and certification.', ARRAY['strategy','corporate development','programme management','contract management','BAFO','tender writing','partnership management','M&A','framework agreement','DPS-FA','defence procurement','executive leadership','board governance'], ARRAY['Strategic planning expertise','Programme management','Contract & framework management','Partnerships & alliance management','Executive & board governance'], 16, 'active'),
  ('competence', 'C4ISR, Communications & PNT', 'Engineering, integration, and operations expertise in command, control, communications, computers, ISR, positioning, navigation, and timing.', ARRAY['C4I engineer','C4ISR architect','comms engineer','PNT specialist','SATCOM operator','RF engineer','tactical data link specialist','network engineer','signals officer','FMN engineer'], ARRAY['C4ISR systems engineering','Tactical data link engineering','PNT specialist','SATCOM engineering','ISR analyst'], 17, 'active'),
  ('competence', 'Cybersecurity', 'Offensive and defensive cyber expertise, secure-by-design engineering, OT/ICS security, and incident response specialism.', ARRAY['cyber engineer','SOC analyst','incident responder','penetration tester','red teamer','threat hunter','security architect','OT security engineer','cryptographer','IEC 62443 specialist','ENISA practitioner'], ARRAY['Security architecture expertise','Penetration testing','SOC analysis','OT/ICS security engineering','Incident response'], 18, 'active'),
