resolved AS (
  SELECT cr.self_type, cr.self_name, ref.id AS ref_id, cr.ord
  FROM co_refs cr
  LEFT JOIN public.ontology_categories ref
    ON ref.type = cr.ref_type AND ref.normalized_name = cr.ref_name
),
agg AS (
  SELECT self_type, self_name, array_agg(ref_id ORDER BY ord) FILTER (WHERE ref_id IS NOT NULL) AS ids
  FROM resolved GROUP BY self_type, self_name
)
UPDATE public.ontology_categories oc
SET co_occurring_category_ids = COALESCE(agg.ids, '{}'::uuid[]),
    updated_at = now()
FROM agg
WHERE oc.type = agg.self_type AND oc.normalized_name = agg.self_name;

-- Post-migration sanity checks
DO $check$
DECLARE v_cats int; v_entries int; v_orphans int; v_empty_co int;
BEGIN
  SELECT COUNT(*) INTO v_cats FROM public.ontology_categories;
  SELECT COUNT(*) INTO v_entries FROM public.ontology_entries WHERE status='active';
  SELECT COUNT(*) INTO v_orphans FROM public.ontology_entries oe
    LEFT JOIN public.ontology_categories oc ON oc.id = oe.category_id
    WHERE oe.category_id IS NULL OR oc.id IS NULL;
  IF v_cats <> 70 THEN RAISE EXCEPTION 'POST: ontology_categories=% (expected 70)', v_cats; END IF;
  IF v_orphans > 0 THEN RAISE EXCEPTION 'POST: % orphan entries', v_orphans; END IF;
  RAISE NOTICE 'POST OK: categories=%, active_entries=%, orphans=%', v_cats, v_entries, v_orphans;
END $check$;
